const email = $json;
const text = `${email.subject} ${email.body}`.toLowerCase();

let riskLevel = "low";
let riskScore = 0.10;
let detectedRiskFactors = "No major risk factor detected.";
let recommendedAction = "No urgent action required.";

if (
  text.includes("refund") ||
  text.includes("unhappy") ||
  text.includes("delayed") ||
  email.sentiment_label === "negative"
) {
  riskLevel = "high";
  riskScore = 0.82;
  detectedRiskFactors = "refund request; delayed service; negative sentiment";
  recommendedAction = "Assign to support manager and respond within 1 hour.";
}

if (
  text.includes("legal complaint") ||
  text.includes("cancel") ||
  text.includes("angry")
) {
  riskLevel = "critical";
  riskScore = 0.96;
  detectedRiskFactors = "legal complaint; cancellation threat; angry language";
  recommendedAction = "Escalate to management immediately and create a priority support ticket.";
}

return [
  {
    json: {
      email_id: email.email_id,
      risk_level: riskLevel,
      risk_score: riskScore,
      detected_risk_factors: detectedRiskFactors,
      recommended_action: recommendedAction
    }
  }
];
